/**
 * Tạo kịch bản TikTok với NGUYÊN TẮC CỘNG ĐỒNG nghiêm ngặt.
 * CƯỠNG ÉP ĐỘ DÀI: 160 - 190 ký tự.
 */
export const generateKocScript = async (
  imageParts: any[], productName: string, keyword: string, scriptTone: string,
  productSize: string, scriptNote: string, scriptLayout: string, gender: string, voice: string,
  addressing: string,
  sceneCount: number
): Promise<ScriptParts> => {
  const ai = getAiClient();
  const voiceDetail = getVoiceDetailedInstruction(voice);

  const prompt = `
    Trong vai 1 Creator chuyên tạo video viral hãy tạo kịch bản bán hàng cho "${productName}". USP: "${keyword}". Layout: "${scriptLayout}". 
    NHÂN VẬT: Giới tính ${gender}, Đặc điểm giọng nói: ${voiceDetail}.

    YÊU CẦU: Đúng ${sceneCount} phần (v1..v${sceneCount}). KHÔNG nhắc bối cảnh/địa điểm.

    !!! QUAN TRỌNG NHẤT (STRICT LENGTH RULE) !!!:
    Mỗi phần kịch bản (v1, v2...) BẮT BUỘC PHẢI CÓ ĐỘ DÀI TỪ 160 ĐẾN 190 KÝ TỰ. 
    - Tuyệt đối KHÔNG ĐƯỢC NGẮN HƠN 160 ký tự.
    - Tuyệt đối KHÔNG ĐƯỢC DÀI HƠN 190 ký tự.
    - Phần CTA điều hướng khách hàng mua hàng tại giỏ hàng góc trái.
    - Văn phong phải cực kỳ khớp với mô tả giọng nói: ${voiceDetail}.
    - Kịch bản phải bắt đầu bằng một câu hỏi.

    QUY TẮC XƯNG HÔ (BẮT BUỘC): Sử dụng cặp xưng hô "${addressing}" (Người nói - Người nghe). 
    Toàn bộ kịch bản phải tuân thủ đúng cặp xưng hô này một cách tự nhiên và xuyên suốt.

    !!! CẢNH BÁO VI PHẠM CỘNG ĐỒNG - TUYỆT ĐỐI KHÔNG SỬ DỤNG CÁC TỪ SAU !!!:
    ${FORBIDDEN_TERMS}
  `;

  const properties: Record<string, any> = {};
  const required: string[] = [];
  for (let i = 1; i <= sceneCount; i++) {
    const key = `v${i}`;
    properties[key] = { type: Type.STRING };
    required.push(key);
  }

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }, ...imageParts.map(p => ({ inlineData: p }))] },
      config: {
        responseMimeType: "application/json",
        responseSchema: { type: Type.OBJECT, properties, required }
      }
    });
    return JSON.parse(cleanJsonResponse(response.text || '{}'));
  } catch (e) {
    const fallback: ScriptParts = {};
    for (let i = 1; i <= sceneCount; i++) fallback[`v${i}`] = '';
    return fallback;
  }
};

/**
 * Tạo lại một phần kịch bản cụ thể (v1, v2...)
 */
export const regenerateKocScriptPart = async (
  imageParts: any[], 
  productName: string, 
  keyword: string, 
  scriptPartKey: string,
  currentPartContent: string,
  fullScript: ScriptParts,
  gender: string, 
  voice: string,
  addressing: string,
  layout: string
): Promise<string> => {
  const ai = getAiClient();
  const voiceDetail = getVoiceDetailedInstruction(voice);

  const prompt = `
    Hãy VIẾT LẠI phần kịch bản "${scriptPartKey}" cho sản phẩm "${productName}".
    Nội dung cũ: "${currentPartContent}".
    Bối cảnh toàn bộ kịch bản: ${JSON.stringify(fullScript)}.

    YÊU CẦU:
    1. Giữ nguyên phong cách và sự logic với các phần khác.
    2. Độ dài bắt buộc: từ 160 đến 190 ký tự.
    3. Giới tính: ${gender}, Đặc điểm giọng nói: ${voiceDetail}.
    4. XƯNG HÔ (BẮT BUỘC): Sử dụng cặp xưng hô "${addressing}" (Người nói - Người nghe).
    5. TUYỆT ĐỐI KHÔNG dùng từ cấm: ${FORBIDDEN_TERMS}
    6. Đảm bảo ngôn từ thu hút và viral hơn bản cũ.

    Trả về duy nhất chuỗi ký tự kịch bản mới.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }, ...imageParts.map(p => ({ inlineData: p }))] }
    });
    return response.text?.trim() || currentPartContent;
  } catch (error) {
    return currentPartContent;
  }
};

/**
 * Tạo hình ảnh với TUÂN THỦ TUYỆT ĐỐI GHI CHÚ NHÂN VẬT & SẢN PHẨM.
 */
export const generateKocImage = async (
  referenceImageParts: any[], 
  faceImagePart: any | null, 
  outfitImagePart: any | null,
  outfitDescription: string, 
  productName: string,
  scriptPart: string, 
  characterDescription: string, 
  userCustomPrompt: string | undefined, 
  gender: string, 
  imageStyle: 'Realistic' | '3D' = 'Realistic', 
  backgroundNote: string = "",
  visualNote: string = "",
  poseLabel: string = "",
  backgroundReferencePart: any | null = null,
  continuityReferencePart: any | null = null
): Promise<string> => {
  const ai = getAiClient();
  const is3D = imageStyle === '3D';

  const lifestyleStyle = "Natural lifestyle shot, daily usage scenario, candid photography, realistic soft natural lighting, casual environment.";

  const baseStyle = is3D 
    ? `High-quality 3D Animation Pixar/Disney style, ${lifestyleStyle} vibe, vibrant but natural colors, expressive character, polished CGI.`
    : `Photorealistic RAW PHOTO, ${lifestyleStyle}, 8k resolution, authentic skin textures, cinematic but realistic natural lighting.`;

  const noProductKeywords = ["không có sản phẩm", "xóa sản phẩm", "không xuất hiện sản phẩm", "bỏ sản phẩm", "không thấy sản phẩm", "no product", "remove product", "without product"];
  const isNoProductRequested = userCustomPrompt && noProductKeywords.some(kw => userCustomPrompt.toLowerCase().includes(kw));

  // !!! STRICT FACE EXCLUSIVITY RULES !!!
  const identityRule = faceImagePart 
    ? `!!! ABSOLUTE FACE IDENTITY RULE (MANDATORY) !!!:
       1. YOU MUST USE THE EXACT facial features, hair color/style, and bone structure from the provided FACE_REFERENCE image.
       2. COMPLETELY IGNORE AND EXCLUDE any faces, eyes, or identities found in OUTFIT_REFERENCE or PRODUCT_REFERENCE images.
       3. If other reference images contain people, treat them ONLY as faceless mannequins; DO NOT COPY their faces or identity.
       4. The character's face MUST come 100% from FACE_REFERENCE only.
       5. The original facial features are preserved 100%, including eyes, nose, lips, skin tone, facial proportions, jawline, and facial structure.
       6. The character's face must always be looking directly into the camera.`
    : `IDENTITY: Adult Vietnamese ${gender} matching description: "${characterDescription}".`;

  const visualRules = `
    CRITICAL VISUAL RULES (STRICT NO-TEXT POLICY):
    1. ABSOLUTELY NO TEXT, NO LETTERS, NO NUMBERS, NO CHARACTERS.
    2. The background must be CLEAN and FREE of signage, posters, labels, or written words.
    3. If the context implies a screen or sign, leave it BLANK or Abstract.
    4. NO UI elements, NO speech bubbles, NO watermarks, NO subtitles.
    5. The image must be purely visual storytelling.
    6. ABSOLUTELY NO ICONS, NO GRAPHICS, NO EMOJIS, NO VISUAL EFFECTS, NO OVERLAYS.
    7. Do NOT simulate TikTok UI or video editing effects. It must look like a RAW PHOTO.

    CRITICAL RESTRICTIONS & RULES: 
    1. NO CHILDREN, NO KIDS, NO BABIES. The subject must be an adult.
    2. ${is3D ? "Must look like high-quality 3D CGI." : "Must look like a real photo."}
    ${isNoProductRequested ? '3. ABSOLUTELY NO PRODUCT/DEVICE IN THIS IMAGE.' : `
    3. STRICT PRODUCT FIDELITY (MANDATORY - TUYỆT ĐỐI):
       - The product "${productName}" MUST MATCH the input reference images provided 1:1.
       - PRESERVE PATTERNS & TEXTURES: Any pattern (họa tiết), logo, or design on the product surface must be preserved.
       - PRESERVE DIMENSIONS: Do not resize or distort the product logic.
       - DO NOT change shape, proportions, or physical parts.
       - LOCK the product appearance exactly to the original photos provided.
       - Hình ảnh tạo ra phải là góc medium shot. nhân vật chiếm 3/4 khung hình và đồng nhất trong tất cả các hình ảnh.
       - QUAN TRỌNG: Đồng nhất về kích thước sản phẩm so sánh với tỷ lệ nhân vật trên khung hình trong tất cả các hình ảnh.
       - CONSISTENT SCALE (QUAN TRỌNG): Đảm bảo kích thước và tỷ lệ của sản phẩm so với khung hình phải đồng nhất 100% qua tất cả các cảnh.
       - Bắt buộc giữ nguyên sản phẩm. Vật thể phải khớp với ảnh gốc 1:1.
       - Always refer to the context, characters, and product (especially product proportions) in the result before creating the image.
       - Quan trọng: hình ảnh tạo ra tuyệt đối không được có logo của GEMINI.
       - ở hình ảnh cuối cùng (CTA) của kịch bản tuyệt đối không được thêm các icon giỏ hàng hay lớp phủ, effect nào lên ảnh.
       - QUAN TRỌNG: sản phẩm là một vật thể cứng, rắn chắc. KHÔNG ĐƯỢC BIẾN DẠNG, KHÔNG ĐƯỢC LÀM BIẾN DẠNG, KHÔNG ĐƯỢC TẠO HOẠT HÌNH CHO THIẾT BỊ. Giữ cho các cạnh sắc nét và tĩnh hoàn hảo. Duy trì tỷ lệ hình học 1:1 với hình ảnh tham khảo.
       - Lưu ý: nếu sản phẩm là thời trang thì chỉ lấy trang phục, bỏ qua khuôn mặt người trong ảnh sản phẩm.
       `}
  `;

  const characterFidelityRule = `
    !!! CRITICAL CHARACTER FIDELITY (PRIORITY) !!!:
    Follow những chi tiết này cho nhân vật: "${characterDescription}".
    Gender: Adult Vietnamese ${gender}.
    - MANDATORY: If description mentions body type or clothing style, apply it 100%. 
  `;

  const outfitRule = outfitImagePart ? `
    OUTFIT: Use textures and style from OUTFIT_REFERENCE. Casual/daily fashion: "${outfitDescription}".
    REMINDER: ONLY use the clothes from OUTFIT_REFERENCE, COMPLETELY IGNORE the face and identity of the person shown in that reference image.
  ` : "";

  const backgroundRule = backgroundReferencePart 
    ? `!!! ABSOLUTE BACKGROUND FIDELITY RULE (100% MANDATORY) !!!:
       - You MUST maintain the EXACT layout, camera angle, perspective, and structural elements from the provided BACKGROUND_REFERENCE.
       - DO NOT change walls, floors, windows, furniture placement, or fixed lighting sources from BACKGROUND_REFERENCE.
       - The background is a fixed, unchanging stage for all shots.
       - Ensure 100% consistency with the static environment shown in the reference.`
    : `ENVIRONMENT: Set the scene in a natural ${backgroundNote || 'daily lifestyle setting'}.`;

  const continuityRule = continuityReferencePart
    ? `!!! SEQUENTIAL CONTINUITY RULE (STRICT) !!!:
       - Use the CONTINUITY_REFERENCE image to ensure the character's appearance, relative position, and the overall color grading matches the previous scene perfectly.
       - The scene must look like the direct continuation of the previous generated frame.`
    : "";

  const poseInstruction = poseLabel ? `CHARACTER POSE (MANDATORY): The person is ${poseLabel}. Ensure the interaction with the product matches this pose perfectly.` : "";

  const sceneInstruction = `SCENE: Context: "${scriptPart}". Action should feel spontaneous and unposed. ${poseInstruction}`;

  const prompt = `
    ${baseStyle} Aspect ratio 9:16. 
    ${characterFidelityRule}
    ${identityRule}
    ${outfitRule}
    ${backgroundRule}
    ${continuityRule}
    ${visualRules}
    ${visualNote ? `VISUAL COMPOSITION: ${visualNote}.` : ""}
    ${sceneInstruction} 
    ${userCustomPrompt || ""}
  `;

  const contents: any[] = [{ text: prompt }];
  if (faceImagePart) contents.push({ inlineData: faceImagePart });
  if (outfitImagePart) contents.push({ inlineData: outfitImagePart });
  if (backgroundReferencePart) contents.push({ inlineData: backgroundReferencePart });
  if (continuityReferencePart) contents.push({ inlineData: continuityReferencePart });

  if (!isNoProductRequested) {
    referenceImageParts.forEach(part => contents.push({ inlineData: part }));
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts: contents },
      config: { imageConfig: { aspectRatio: "9:16" } }
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData?.data) return `data:image/png;base64,${part.inlineData.data}`;
    }
    throw new Error("Fail");
  } catch (error) { throw error; }
};

/**
 * Generates a video prompt for VEO-3 model based on script and visual context.
 */
export const generateKocVeoPrompt = async (
  productName: string, 
  scriptText: string, 
  gender: string, 
  voice: string,
  productImageBase64?: string,
  generatedImageBase64?: string,
  isNoProductRequested: boolean = false,
  imageStyle: 'Realistic' | '3D' = 'Realistic'
): Promise<string> => {
  const ai = getAiClient();
  const is3D = imageStyle === '3D';
  const voiceDetail = getVoiceDetailedInstruction(voice);
  const voiceGender = gender === 'Nữ' ? 'Female' : 'Male';

  const productInteractionRule = isNoProductRequested
    ? `PHẦN 2: HÀNH ĐỘNG & TƯƠNG TÁC (QUAN TRỌNG):
      - TUYỆT ĐỐI KHÔNG xuất hiện sản phẩm "${productName}".
      - Cách nhân vật di chuyển, nói chuyện và tương tác phù hợp với kịch bản: "${scriptText}".`
    : `PHẦN 2: HÀNH ĐỘNG & TƯƠNG TÁC (QUAN TRỌNG):
      - Nhân vật đang cầm trên tay sản phẩm "${productName}".
      - Cách nhân vật di chuyển, nói chuyện và tương tác phù hợp với kịch bản: "${scriptText}".
      - [QUAN TRỌNG: sản phẩm là một vật thể cứng, rắn chắc. KHÔNG ĐƯỢC BIẾN DẠNG, KHÔNG ĐƯỢC LÀM BIẾN DẠNG, KHÔNG ĐƯỢC TẠO HOẠT HÌNH CHO THIẾT BỊ. Giữ cho các cạnh sắc nét và tĩnh hoàn hảo. Duy trì tỷ lệ hình học 1:1 với hình ảnh tham khảo].
      - [SẢN PHẨM PHẢI GIỐNG ẢNH THAM CHIẾU 100%, KHÔNG BIẾN DẠNG]`;

  const instructionPrompt = `
  Nhiệm vụ: Viết một lời nhắc (Prompt) chi tiết để tạo video AI (VEO-3) dài 8 giây cho video KOC Review.
  PHONG CÁCH VIDEO: ${is3D ? "3D Animation / CGI Style" : "Photorealistic / Real Life Style"}.
  !!! CRITICAL IDENTITY RULE !!!: Maintain 100% facial and appearance consistency with the face provided in the reference image (0. Ảnh mặt mẫu). EXCLUDE any facial features or identity from background outfit shots or product images.

  CẤU TRÚC PROMPT:
  PHẦN 1: NHÂN VẬT & DIỆN MẠO (BẮT BUỘC NHẤT QUÁN). Nhân vật người Việt Nam. Đặc điểm diễn xuất và giọng nói: ${voiceDetail}. ${is3D ? "Phong cách hoạt hình 3D Pixar/Disney." : "Phong cách người thật chân thực."}
  ${productInteractionRule}
  PHẦN 3: BỐI CẢNH & ÁNH SÁNG. Một không gian sống hiện đại, sạch sẽ. ${is3D ? "Môi trường 3D sống động." : "Ánh sáng điện ảnh chân thực."}
  PHẦN 4: CHUYỂN ĐỘNG MÁY ẢNH (9:16). Static camera movement. tuyệt đối không thay đổi bối cảnh và nhân vật trong suốt 8s.
  PHẦN 5: LỜI THOẠI (DÙNG CHO ĐỒNG BỘ): ✨ Model speaks in ${voiceDetail} characteristics (${voiceGender}): "${scriptText}"
  PHẦN 6: CHẤT LƯỢNG KỸ THUẬT: 4K, ${is3D ? "3D Animation, Masterpiece CGI, 60fps" : "Realistic, Cinematic Lighting, Photorealistic, 60fps"}, Không có nhạc nền, Tuyệt đối không hiệu ứng chuyển cảnh hay lật trang ở cuối video.

  YÊU CẦU: Trả về 1 dòng Tiếng Anh duy nhất (trừ phần lời thoại). Không xuống dòng.`;

  const contents: any[] = [{ text: instructionPrompt }];
  if (productImageBase64) {
    contents.push({ inlineData: { mimeType: 'image/png', data: productImageBase64.split(',')[1] || productImageBase64 } });
  }
  if (generatedImageBase64) {
    contents.push({ inlineData: { mimeType: 'image/png', data: generatedImageBase64.split(',')[1] || generatedImageBase64 } });
  }

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: contents }
    });
    return response.text?.trim().replace(/\n/g, ' ') || "";
  } catch (error) {
    console.error("Video prompt generation error", error);
    return "Error generating video prompt.";
  }
};

