                 className="text-[10px] text-orange-300 hover:text-orange-200 disabled:opacity-50"
               >
                 {videoPrompt.translating ? 'Translating...' : 'Dịch TV'}
               </button>
               <button 
                 onClick={() => navigator.clipboard.writeText(videoPrompt.text)}
                 className="text-[10px] text-slate-400 hover:text-white"
               >
                 Copy
               </button>
             </div>
           </div>
           <textarea 
             readOnly 
             className="w-full h-32 bg-slate-950 text-slate-300 text-[10px] p-2 rounded border border-slate-800 focus:outline-none resize-none mb-2 font-mono"
             value={videoPrompt.text}
           />

           {/* Translated Prompt */}
           {videoPrompt.translatedText && (
             <div className="mt-2 pt-2 border-t border-slate-800">
               <div className="flex justify-between items-center mb-2">
                 <h4 className="text-orange-500 text-[10px] uppercase font-bold tracking-wider">Prompt (VN)</h4>
                 <button 
                   onClick={() => navigator.clipboard.writeText(videoPrompt.translatedText || '')}
                   className="text-[10px] text-slate-400 hover:text-white"
                 >
                   Copy
                 </button>
               </div>
               <textarea 
                 readOnly 
                 className="w-full h-32 bg-slate-950 text-slate-300 text-[10px] p-2 rounded border border-slate-800 focus:outline-none resize-none font-medium"
                 value={videoPrompt.translatedText}
               />
             </div>
           )}
        </div>
      )}
    </div>
  );
};

